//Generated by Claude 4.6 & Gemini (Refactored for Student Photo, Dynamic Report Card Matrix, Native PDF Streaming & Interactive Assignment Breakdown Modal)
const express = require('express');
const StudentVue = require('studentvue.js');
const path = require('path');

const app = express();
const port = process.env.PORT || 3000;

app.use(express.json());

function parse(data) {
  return typeof data === 'string' ? JSON.parse(data) : data;
}

function fuzzyFind(obj, keywords) {
  if (!obj) return 'N/A';
  for (const kw of keywords) {
    const foundKey = Object.keys(obj).find(k => k.toLowerCase().includes(kw.toLowerCase()));
    if (foundKey && obj[foundKey]) {
      return obj[foundKey];
    }
  }
  return 'N/A';
}

function findAllMessages(obj, results = []) {
  if (!obj || typeof obj !== 'object') return results;
  if (obj.Subject || obj.SubjectNoHTML || obj['@_Subject']) {
    results.push(obj);
    return results;
  }
  for (const key in obj) {
    if (typeof obj[key] === 'object') {
      findAllMessages(obj[key], results);
    }
  }
  return results;
}

function findGPADeep(obj) {
  if (!obj || typeof obj !== 'object') return null;
  if (Array.isArray(obj)) {
    for (const item of obj) {
      const found = findGPADeep(item);
      if (found) return found;
    }
    return null;
  }
  for (const key in obj) {
    const val = obj[key];
    if (val === null || val === undefined) continue;
    if (key.toLowerCase().includes('gpa')) {
      if (typeof val !== 'object') return val; 
      const leaf = val.Value || val['@_Value'] || val.Score || val['@_Score'] || val['#text'];
      if (leaf && typeof leaf !== 'object') return leaf;
      const innerFound = findGPADeep(val);
      if (innerFound) return innerFound;
    }
    if (typeof val === 'object') {
      const found = findGPADeep(val);
      if (found) return found;
    }
  }
  return null;
}

function calculateTermGPAManually(grades) {
  if (!grades || grades.length === 0) return 'N/A';
  const gradeScale = { 'A': 4.0, 'B': 3.0, 'C': 2.0, 'D': 1.0, 'F': 0.0, 'E': 0.0 };
  let totalPoints = 0;
  let gradedClassesCount = 0;
  for (const course of grades) {
    if (!course.grade) continue;
    const baseLetter = course.grade.trim().charAt(0).toUpperCase();
    if (baseLetter in gradeScale) {
      totalPoints += gradeScale[baseLetter];
      gradedClassesCount++;
    }
  }
  return gradedClassesCount > 0 ? (totalPoints / gradedClassesCount).toFixed(2) : 'N/A';
}

app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'index.html'));
});

app.get('/api/search', async (req, res) => {
  const zip = req.query.zip;
  if (!zip) return res.status(400).json({ error: "No zip code provided" });
  try {
    const rawResults = await StudentVue.getDistrictUrls(zip.trim());
    const results = parse(rawResults);
    const districts = results?.DistrictLists?.DistrictInfos?.DistrictInfo;
    if (!districts) {
      return res.status(404).json({ error: "No districts found for that zip code." });
    }
    const districtList = Array.isArray(districts) ? districts : [districts];
    const cleanList = districtList.map(d => ({
      name: d.Name || 'Unknown',
      url: d.PvueURL || 'N/A'
    }));
    res.json({ districts: cleanList });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.post('/api/login', async (req, res) => {
  const { url, user, pass } = req.body;
  if (!url || !user || !pass) return res.status(400).json({ success: false, message: "Missing credentials." });

  try {
    const client = await StudentVue.login(url, user, pass);

    // 1. Fetch Student Info
    const infoData = await client.getStudentInfo();
    const parsedInfo = parse(infoData);
    const info = parsedInfo?.StudentInfo;
    let studentInfo = null;
    
    if (info) {
      let photoBase64 = 'N/A';
      if (info.Photo) {
        photoBase64 = typeof info.Photo === 'object' 
          ? (info.Photo.Value || info.Photo['#text'] || info.Photo['@_Value'] || 'N/A') 
          : info.Photo;
      }
      studentInfo = {
        name:   fuzzyFind(info, ['formattedname', 'displayname', 'name']),
        grade:  fuzzyFind(info, ['grade']),
        school: fuzzyFind(info, ['schoolname', 'currentschool', 'organization', 'school', 'org', 'campus']),
        photo:  photoBase64
      };
    }

    // 2. NEW CONTENT: Fetch Schedule XML/JSON Data
    let schedule = [];
    try {
      const scheduleData = await client.getSchedule();
      const parsedSchedule = parse(scheduleData);
      const classListing = parsedSchedule?.Schedule?.ClassLists?.ClassListing;
      if (classListing) {
        const list = Array.isArray(classListing) ? classListing : [classListing];
        schedule = list.map(c => ({
          period:  c.Period      || c['@_Period']      || '?',
          course:  c.CourseTitle || c['@_CourseTitle'] || 'Unknown',
          room:    c.RoomNum     || c['@_RoomNum']     || 'N/A',
          teacher: c.TeacherName || c['@_TeacherName'] || 'Unknown'
        }));
        // Sort courses logically ascending by period number
        schedule.sort((a, b) => String(a.period).localeCompare(String(b.period), undefined, {numeric: true}));
      }
    } catch (e) {
      console.warn("Class schedule extraction failed or wasn't published:", e.message);
    }

    // 3. Fetch Grades & GPA
    const gradeData = await client.getGradebook();
    const parsedGradebook = parse(gradeData);
    const gradebookRoot = parsedGradebook?.Gradebook;
    const courses = gradebookRoot?.Courses?.Course;
    
    let discoveredGpa = findGPADeep(parsedGradebook) || findGPADeep(parsedInfo);
    let finalGpa = (discoveredGpa && discoveredGpa !== 'N/A') ? String(discoveredGpa).trim() : 'N/A';

    let grades = [];
    if (courses) {
      const courseList = Array.isArray(courses) ? courses : [courses];
      grades = courseList.map(course => {
        const currentMark = course.Marks?.Mark?.[0] || course.Marks?.Mark;
        const rawMarksArray = Array.isArray(course.Marks?.Mark) ? course.Marks.Mark : (course.Marks?.Mark ? [course.Marks.Mark] : []);
          
        const historyData = rawMarksArray.map(m => ({
          termName: m.ReportingPeriodName || m['@_ReportingPeriodName'] || 'Term',
          grade:    m.CalculatedScoreString || 'N/A',
          raw:      m.CalculatedScoreRaw    || 'N/A'
        }));

        let rawAssignments = course.Assignments?.Assignment || currentMark?.Assignments?.Assignment;
        if (!rawAssignments) {
          for (const mark of rawMarksArray) {
            if (mark.Assignments?.Assignment) {
              rawAssignments = mark.Assignments.Assignment;
              break;
            }
          }
        }

        const assignmentList = Array.isArray(rawAssignments) ? rawAssignments : (rawAssignments ? [rawAssignments] : []);
        const parsedAssignments = assignmentList.map(assign => {
          let scoreVal = assign.Points || assign['@_Points'] || assign.ScoreString || assign['@_ScoreString'] || assign.ResultString || assign['@_ResultString'] || 'N/A';
          return {
            name: assign.Measure || assign['@_Measure'] || assign.Title || assign['@_Title'] || 'Assignment',
            date: assign.DueDate || assign['@_DueDate'] || assign.Date || assign['@_Date'] || 'N/A',
            score: scoreVal,
            type: assign.Type || assign['@_Type'] || ''
          };
        });

        return {
          title:   course.Title  || 'Unknown',
          period:  course.Period || '?',
          grade:   currentMark?.CalculatedScoreString || 'N/A',
          raw:     currentMark?.CalculatedScoreRaw    || 'N/A',
          history: historyData,
          assignments: parsedAssignments
        };
      });
    }

    if (finalGpa === 'N/A' && grades.length > 0) {
      finalGpa = calculateTermGPAManually(grades) + " (Unweighted)";
    }

    // 4. Fetch System Notifications
    const mailData = await client.getMessages();
    const parsedMail = parse(mailData);
    const discoveredMessages = findAllMessages(parsedMail);
                     
    let notifications = [];
    if (discoveredMessages && discoveredMessages.length > 0) {
      notifications = discoveredMessages.map(m => ({
        from:    m.From       || m['@_From']       || m.Module  || 'System Alert',
        subject: m.Subject    || m['@_Subject']    || m.SubjectNoHTML || '(No Content)',
        date:    m.BeginDate  || m['@_BeginDate']  || '',
        read:    String(m.Read || m['@_Read'] || 'false').toLowerCase() === 'true' ? 'true' : 'false'
      }));
    }

    res.json({ success: true, studentInfo, grades, gpa: finalGpa, notifications, schedule });

  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
});

app.post('/api/report-card/download', async (req, res) => {
  const { url, user, pass } = req.body;
  if (!url || !user || !pass) return res.status(400).json({ success: false, message: "Missing credentials." });
  try {
    const client = await StudentVue.login(url, user, pass);
    const rawDocumentXML = await client.request.execute("ReportCards", {});
    const parsedDocument = parse(rawDocumentXML);
    const reportCardData = parsedDocument?.ReportCards?.ReportCardsList?.ReportCard;
    if (!reportCardData) {
      return res.status(404).json({ success: false, message: "No official PDF report cards published by administration yet." });
    }
    const targetDoc = Array.isArray(reportCardData) ? reportCardData[0] : reportCardData;
    const base64PDF = targetDoc?.Base64DocumentData || targetDoc['@_Base64DocumentData'];
    if (!base64PDF || base64PDF === 'N/A') {
      return res.status(404).json({ success: false, message: "PDF document data stream was empty." });
    }
    const pdfBuffer = Buffer.from(base64PDF, 'base64');
    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', 'inline; filename="Official_Report_Card.pdf"');
    return res.send(pdfBuffer);
  } catch (err) {
    res.status(500).json({ success: false, message: "Failed to compile document: " + err.message });
  }
});

app.listen(port, () => {
  console.log(`Web interface running! Go to: http://localhost:${port}`);
});